@* Step indicator bar showing progress through the wizard *@

<nav class="step-indicator" aria-label="Application progress">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var stepIndex = i;
        var status = GetStepStatus(stepIndex);
        <button class="step @status"
                disabled="@(status == "future")"
                @onclick="() => OnStepClicked.InvokeAsync(stepIndex)"
                aria-current="@(stepIndex == CurrentStep ? "step" : null)">
            <span class="step-number">
                @if (status == "completed")
                {
                    <span class="checkmark">&#10003;</span>
                }
                else
                {
                    @(stepIndex + 1)
                }
            </span>
            <span class="step-label">@StepNames[stepIndex]</span>
        </button>
        @if (i < StepNames.Length - 1)
        {
            <span class="step-connector @(i < CurrentStep ? "completed" : "")"></span>
        }
    }
</nav>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public int HighestCompletedStep { get; set; }
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private string GetStepStatus(int step)
    {
        if (step == CurrentStep) return "current";
        if (step <= HighestCompletedStep) return "completed";
        return "future";
    }
}

nav.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 0;
    margin-bottom: 2rem;
    flex-wrap: wrap;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.35rem;
    background: none;
    border: none;
    cursor: pointer;
    padding: 0.5rem 0.75rem;
    min-width: 6rem;
}

.step:disabled {
    cursor: default;
}

.step-number {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 2.2rem;
    height: 2.2rem;
    border-radius: 50%;
    font-weight: 600;
    font-size: 0.95rem;
    transition: all 0.2s;
}

.step.current .step-number {
    background: #2563eb;
    color: #fff;
    box-shadow: 0 0 0 3px rgba(37, 99, 235, 0.25);
}

.step.completed .step-number {
    background: #16a34a;
    color: #fff;
}

.step.future .step-number {
    background: #e5e7eb;
    color: #9ca3af;
}

.step-label {
    font-size: 0.78rem;
    font-weight: 500;
    white-space: nowrap;
}

.step.current .step-label { color: #2563eb; }
.step.completed .step-label { color: #16a34a; }
.step.future .step-label { color: #9ca3af; }

.checkmark { font-size: 1.1rem; }

.step-connector {
    width: 2.5rem;
    height: 2px;
    background: #e5e7eb;
    align-self: center;
    margin-bottom: 1.4rem;
}

.step-connector.completed {
    background: #16a34a;
}

