+    padding: 0.5rem 0.75rem;
+    min-width: 6rem;
+}
+
+.step:disabled {
+    cursor: default;
+}
+
+.step-number {
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    width: 2.2rem;
+    height: 2.2rem;
+    border-radius: 50%;
+    font-weight: 600;
+    font-size: 0.95rem;
+    transition: all 0.2s;
+}
+
+.step.current .step-number {
+    background: #2563eb;
+    color: #fff;
+    box-shadow: 0 0 0 3px rgba(37, 99, 235, 0.25);
+}
+
+.step.completed .step-number {
+    background: #16a34a;
+    color: #fff;
+}
+
+.step.future .step-number {
+    background: #e5e7eb;
+    color: #9ca3af;
+}
+
+.step-label {
+    font-size: 0.78rem;
+    font-weight: 500;
+    white-space: nowrap;
+}
+
+.step.current .step-label { color: #2563eb; }
+.step.completed .step-label { color: #16a34a; }
+.step.future .step-label { color: #9ca3af; }
+
+.checkmark { font-size: 1.1rem; }
+
+.step-connector {
+    width: 2.5rem;
+    height: 2px;
+    background: #e5e7eb;
+    align-self: center;
+    margin-bottom: 1.4rem;
+}
+
+.step-connector.completed {
+    background: #16a34a;
+}
+

