arguments.file_text:
@* Step 1: Personal information form *@
@using sv_ce427f325afd4f929200a29825550388.Models

<div class="step-content">
    <h2>Personal Information</h2>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="error-banner">@errorMessage</div>
    }

    <div class="form-group">
        <label>Full Name *</label>
        <input type="text" @bind="Model.FullName" @bind:event="oninput" placeholder="Your full name" />
    </div>

    <div class="form-group">
        <label>Email Address *</label>
        <input type="email" @bind="Model.Email" @bind:event="oninput" placeholder="you@example.com" />
        @if (isValidatingEmail)
        {
            <span class="field-hint">Validating email…</span>
        }
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Phone *</label>
            <input type="tel" @bind="Model.Phone" @bind:event="oninput" placeholder="Phone number" />
        </div>
        <div class="form-group">
            <label>Address *</label>
            <input type="text" @bind="Model.Address" @bind:event="oninput" placeholder="Your address" />
        </div>
    </div>

    <div class="step-actions">
        <button class="btn-primary" @onclick="HandleNext" disabled="@isValidatingEmail">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
