@* Step 2: Work history with dynamic entries *@
@using sv_ce427f325afd4f929200a29825550388.Models

<div class="step-content">
    <h2>Work History</h2>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="error-banner">@errorMessage</div>
    }

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryForm Entry="Entries[index]"
                       Index="index + 1"
                       CanRemove="Entries.Count > 1"
                       OnRemove="() => RemoveEntry(index)" />
    }

    <button type="button" class="btn-secondary" @onclick="AddEntry">+ Add Another Position</button>

    <div class="step-actions">
        <button class="btn-outline" @onclick="OnBack">Back</button>
        <button class="btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? errorMessage;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        errorMessage = null;

        if (!Entries.All(e => e.IsValid()))
        {
            errorMessage = "Please fill in all required fields (company, title, start date) for each position.";
            return;
        }

        await OnNext.InvokeAsync();
    }
}

