toolArgs.file_text:
@* Step 5: Review all data and submit *@
@using sv_ce427f325afd4f929200a29825550388.Models

<div class="step-content">
    <h2>Review &amp; Submit</h2>
    <p class="step-description">Please review your application before submitting.</p>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="error-banner">@errorMessage</div>
    }

    @if (IsSubmitted)
    {
        <div class="success-banner">
            <h3>🎉 Application Submitted!</h3>
            <p>Your application has been received. Your confirmation number is <strong>#@ApplicationId</strong>.</p>
        </div>
    }
    else
    {
        <!-- Personal Info -->
        <section class="review-section">
            <div class="review-header">
                <h3>Personal Information</h3>
                <button class="btn-link" @onclick="() => OnEditStep.InvokeAsync(0)">Edit</button>
            </div>
            <dl class="review-grid">
                <dt>Full Name</dt><dd>@Personal.FullName</dd>
                <dt>Email</dt><dd>@Personal.Email</dd>
                <dt>Phone</dt><dd>@Personal.Phone</dd>
                <dt>Address</dt><dd>@Personal.Address</dd>
            </dl>
        </section>

        <!-- Work History -->
        <section class="review-section">
            <div class="review-header">
                <h3>Work History</h3>
                <button class="btn-link" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
            </div>
            @foreach (var entry in WorkEntries)
            {
                <div class="review-work-entry">
                    <strong>@entry.Title</strong> at @entry.Company
                    <span class="review-dates">
                        @entry.StartDate?.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </span>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="review-description">@entry.Description</p>
                    }
                </div>
            }
        </section>

        <!-- References -->
        <section class="review-section">
            <div class="review-header">
                <h3>References</h3>
                <button class="btn-link" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</button>
            </div>
            @foreach (var r in References)
            {
                <div class="review-reference">
                    <strong>@r.Name</strong> — @r.Relationship<br />
                    @r.Email &bull; @r.Phone
                </div>
            }
        </section>

        <!-- Cover Letter -->
        <section class="review-section">
            <div class="review-header">
                <h3>Cover Letter</h3>
                <button class="btn-link" @onclick="() => OnEditStep.InvokeAsync(3)">Edit</button>
            </div>
            <p class="review-cover-letter">@CoverLetter</p>
        </section>

        <div class="step-actions">
            <button class="btn-outline" @onclick="OnBack">Back</button>
            <button class="btn-primary btn-submit" @onclick="HandleSubmit" disabled="@isSubmitting">
                @if (isSubmitting)
                {
                    <span>Submitting…</span>
                }
                else
                {
                    <span>Submit Application</span>
                }
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnEditStep { get; set; }
    [Parameter, EditorRequired] public EventCallback OnSubmit { get; set; }
    [Parameter] public bool IsSubmitted { get; set; }
    [Parameter] public int ApplicationId { get; set; }

    private bool isSubmitting;
    private string? errorMessage;

    private async Task HandleSubmit()
    {
        errorMessage = null;
        isSubmitting = true;

        try
        {
            await OnSubmit.InvokeAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

